namespace BgCommon;/// <summary>/// 文件系统实用工具类，提供可读文件大小转换、目录读写状态检查及目录拷贝功能./// </summary>public static class FileSystemUtil{    private static readonly string[] SizeUnits = ["B ", "KB", "MB", "GB", "TB", "PB", "EB"];    /// <summary>    /// 返回指定文件大小的人类可读字符串表示形式.    /// </summary>    /// <param name="bytes">以字节为单位的文件大小.</param>    /// <param name="decimalPlaces">输出中显示的小数位数.</param>    /// <returns>格式化后的文件大小字符串.</returns>    /// <exception cref="ArgumentOutOfRangeException">当 <paramref name="bytes"/> 小于 0 时抛出.</exception>    public static string GetReadableFileSize(long bytes, int decimalPlaces = 3)    {        // 校验字节数是否小于 0.        if (bytes < 0)        {            throw new ArgumentOutOfRangeException(nameof(bytes), "文件大小不能为负数.");        }        double fileSizeWithUnit = bytes;        int unitIndex = 0;        // 循环缩小数值直至匹配到合适的单位（B, KB, MB 等）.        while (fileSizeWithUnit >= 1024 && unitIndex < SizeUnits.Length - 1)        {            unitIndex++;            fileSizeWithUnit /= 1024;        }        // 根据指定的小数位数构造格式化字符串.        string format = "0." + new string('#', decimalPlaces);        // 返回格式化后的数值及对应的单位.        return $"{fileSizeWithUnit.ToString(format)} {SizeUnits[unitIndex]}";    }    /// <summary>    /// 确定目录路径是否可读.    /// </summary>    /// <param name="path">要检查的目录路径.</param>    /// <returns>如果目录存在且可读则返回 true，否则返回 false.</returns>    public static bool IsDirectoryReadable(string path)    {        // 校验路径参数是否为 null.        ArgumentNullException.ThrowIfNull(path, nameof(path));        try        {            // 尝试枚举目录条目，若无权限则会抛出异常.            _ = Directory.EnumerateFileSystemEntries(path).Any();            return true;        }        catch        {            // 捕获权限不足或目录不存在等任何异常.            return false;        }    }    /// <summary>    /// 确定目录路径是否可写.    /// </summary>    /// <param name="path">要检查的目录路径.</param>    /// <returns>如果目录存在且可写则返回 true，否则返回 false.</returns>    public static bool IsDirectoryWritable(string path)    {        // 校验路径参数是否为 null.        ArgumentNullException.ThrowIfNull(path, nameof(path));        try        {            // 尝试在目录下创建一个随机命名的临时文件并设置关闭时删除.            using var fileStream = File.Create(Path.Combine(path, Path.GetRandomFileName()), 1, FileOptions.DeleteOnClose);            return true;        }        catch        {            // 捕获权限不足或目录不可写等任何异常.            return false;        }    }    /// <summary>    /// 拷贝目录。当拷贝文件且目标位置已存在同名文件时，此方法将抛出异常.    /// </summary>    /// <param name="sourceDir">源目录路径.</param>    /// <param name="destinationDir">目标目录路径.</param>    /// <param name="recursive">是否递归拷贝子目录.</param>    /// <exception cref="DirectoryNotFoundException">当源目录不存在时抛出.</exception>    public static void CopyDirectory(string sourceDir, string destinationDir, bool recursive)    {        // 校验源目录和目标目录参数是否为 null.        ArgumentNullException.ThrowIfNull(sourceDir, nameof(sourceDir));        ArgumentNullException.ThrowIfNull(destinationDir, nameof(destinationDir));        DirectoryInfo sourceDirInfo = new DirectoryInfo(sourceDir);        // 检查源目录是否在物理磁盘上存在.        if (!sourceDirInfo.Exists)        {            throw new DirectoryNotFoundException($"未找到源目录: {sourceDirInfo.FullName}");        }        // 如果目标目录不存在，则递归创建所有层级.        Directory.CreateDirectory(destinationDir);        // 拷贝当前层级的所有文件.        foreach (FileInfo sourceFile in sourceDirInfo.GetFiles())        {            string targetFilePath = Path.Combine(destinationDir, sourceFile.Name);            sourceFile.CopyTo(targetFilePath);        }        // 如果需要递归拷贝，则处理子目录.        if (recursive)        {            DirectoryInfo[] sourceSubDirInfos = sourceDirInfo.GetDirectories();            foreach (DirectoryInfo subDirInfo in sourceSubDirInfos)            {                string targetSubDirPath = Path.Combine(destinationDir, subDirInfo.Name);                // 递归调用自身进行子目录拷贝.                CopyDirectory(subDirInfo.FullName, targetSubDirPath, true);            }        }    }}